{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from single-recipient to multi-recipient shipments. This is a fundamental change to the Shipment aggregate root, affecting the cardinality of its most critical relationship. The change impacts 2 million existing production records and external partner API contracts.",
    "bounded_context": "Shipment Management / Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "An aggregate root representing a single consignment of goods moving from origin to destination(s). Owns the lifecycle of delivery." },
      { "term": "Recipient", "definition": "A value object or entity representing a person or organization receiving a delivery, including name, address, phone number, and delivery preferences." },
      { "term": "Delivery Preferences", "definition": "Recipient-specific instructions governing how and when delivery should occur (e.g., time windows, safe place, signature required, authority to leave)." },
      { "term": "Primary Recipient", "definition": "The first or default recipient on a shipment. For backward compatibility, this is the single recipient on legacy shipments." },
      { "term": "Multi-Recipient Shipment", "definition": "A shipment with two or more recipients, each potentially at different addresses with different delivery preferences." },
      { "term": "Shipment Status", "definition": "The lifecycle state of a shipment. In a multi-recipient model, the question of whether status is per-shipment or per-recipient becomes a critical design decision." },
      { "term": "Partner API", "definition": "External integrations that consume shipment data in the current single-recipient format." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A shipment without a recipient is physically meaningless — goods must be delivered to someone. This is a real-world constraint, not a policy choice.",
      "testable_assertion": "Creating or updating a Shipment with zero Recipients must be rejected by the domain model."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment must have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum data required to physically execute a delivery. Without them, a courier cannot deliver.",
      "testable_assertion": "Adding a Recipient with a null or empty name, address, or phone number must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Delivery preferences belong to the Recipient, not to the Shipment.",
      "invariant": true,
      "invariant_justification": "In the multi-recipient model, each recipient may have different delivery constraints (e.g., one requires signature, another allows safe-place). Preferences at the shipment level would be physically incorrect — delivery happens per-address.",
      "testable_assertion": "Each Recipient entity independently stores and enforces its own delivery preferences."
    },
    {
      "id": "BR-4",
      "rule": "All existing single-recipient shipments must remain valid and queryable after migration with no behavioral change.",
      "invariant": true,
      "invariant_justification": "Data loss or corruption of 2 million production records would be a system integrity violation, not a policy decision.",
      "testable_assertion": "After migration, querying any pre-existing shipment returns its original recipient with identical name, address, phone, and any existing preferences."
    },
    {
      "id": "BR-5",
      "rule": "A Shipment must define a delivery sequence or routing order when it has multiple recipients.",
      "invariant": false,
      "invariant_justification": "The business may decide to allow unordered multi-drop or enforce strict sequencing — this is a logistics policy, not a physical constraint.",
      "testable_assertion": "A multi-recipient shipment either has an explicit recipient order or the system applies a default ordering policy."
    },
    {
      "id": "BR-6",
      "rule": "Each Recipient on a Shipment must have an independently trackable delivery status.",
      "invariant": true,
      "invariant_justification": "If recipient A receives their delivery but recipient B does not, the system must reflect this. A single status for the entire shipment would misrepresent physical reality and break proof-of-delivery accuracy.",
      "testable_assertion": "Delivering to Recipient A and failing to deliver to Recipient B results in distinct statuses per recipient, and the overall Shipment status reflects partial completion."
    },
    {
      "id": "BR-7",
      "rule": "External partner APIs must continue to receive shipment data without breaking changes until partners have migrated.",
      "invariant": false,
      "invariant_justification": "This is a contractual and business-relationship constraint, not a physical one. It can be relaxed through partner negotiation and versioned rollout.",
      "testable_assertion": "Partner API endpoints continue to return single-recipient format for existing integrations. A new API version exposes the multi-recipient structure."
    },
    {
      "id": "BR-8",
      "rule": "Removing a Recipient from a Shipment is only permitted if the Recipient has not yet been delivered to.",
      "invariant": true,
      "invariant_justification": "Once a physical delivery has occurred, the recipient is part of the historical record. Removing them would corrupt proof-of-delivery and audit trail — a data integrity violation.",
      "testable_assertion": "Attempting to remove a Recipient whose status is 'delivered' must be rejected. Removing a Recipient whose status is 'pending' is allowed as long as BR-1 (at least one recipient) is maintained."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator provides two or more Recipients with distinct addresses and delivery preferences",
      "then": "The Shipment is created with all Recipients, each preserving their individual preferences, and the system assigns per-recipient delivery statuses."
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment created before the migration",
      "when": "The Shipment is queried via the API",
      "then": "The response includes exactly one Recipient with the original name, address, phone number, and the Shipment behaves identically to pre-migration behavior."
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment where delivery to Recipient A succeeds but delivery to Recipient B fails",
      "when": "The Shipment status is queried",
      "then": "Recipient A shows 'delivered', Recipient B shows the failure status, and the overall Shipment status reflects 'partially delivered' or equivalent."
    },
    {
      "id": "AC-4",
      "given": "An external partner API consumer using the current single-recipient format",
      "when": "They request shipment data for a multi-recipient Shipment",
      "then": "The legacy API version returns only the primary recipient (backward-compatible), while a new API version returns all recipients."
    },
    {
      "id": "AC-5",
      "given": "A user attempts to create a Shipment with zero Recipients",
      "when": "The create request is submitted",
      "then": "The request is rejected with a validation error stating at least one Recipient is required."
    },
    {
      "id": "AC-6",
      "given": "A multi-recipient Shipment with one delivered and one pending Recipient",
      "when": "A user attempts to remove the delivered Recipient",
      "then": "The removal is rejected because delivered Recipients are part of the immutable delivery record."
    },
    {
      "id": "AC-7",
      "given": "The data migration is executed against 2 million existing shipments",
      "when": "Migration completes",
      "then": "All 2 million shipments have their single recipient preserved in the new multi-recipient structure with zero data loss, and rollback is possible."
    }
  ],

  "edge_cases": [
    {
      "scenario": "Two Recipients on the same Shipment share the same address but have different delivery preferences",
      "expected_behavior": "Both Recipients are treated as distinct entities. The courier must fulfill each Recipient's individual preferences even though the physical destination is the same."
    },
    {
      "scenario": "A multi-recipient Shipment where one Recipient's address becomes invalid (e.g., building demolished) after creation",
      "expected_behavior": "The invalid Recipient enters a failure/exception state independently. Other Recipients on the Shipment are unaffected and delivery proceeds."
    },
    {
      "scenario": "A Shipment has 50+ Recipients (bulk/distribution use case)",
      "expected_behavior": "The system must define and enforce a maximum recipient count per Shipment to prevent performance degradation and to distinguish a multi-drop Shipment from a distribution manifest, which is a different bounded context."
    },
    {
      "scenario": "External partner receives a webhook for a multi-recipient Shipment but only understands the single-recipient format",
      "expected_behavior": "Webhook payloads for legacy partners must be transformed to the single-recipient format (primary recipient only), or the partner must be on a new webhook version. Silent data loss (dropping extra recipients without notification) is unacceptable."
    },
    {
      "scenario": "A Recipient is added to a Shipment that is already in-transit",
      "expected_behavior": "Business must define whether mid-transit recipient addition is allowed. If allowed, the routing/sequencing must be recalculated. If disallowed, the addition is rejected once the Shipment leaves a defined state (e.g., 'dispatched')."
    },
    {
      "scenario": "Pricing and billing: does a multi-recipient Shipment cost more than a single-recipient Shipment?",
      "expected_behavior": "The pricing model must account for additional stops. A Shipment with 3 Recipients at 3 addresses is fundamentally different from 1 Recipient at 1 address in terms of cost, time, and fuel."
    },
    {
      "scenario": "Proof of delivery: each Recipient requires independent proof (signature, photo)",
      "expected_behavior": "Proof-of-delivery artifacts must be captured and stored per Recipient, not per Shipment. A single proof-of-delivery for a multi-recipient Shipment is legally and operationally insufficient."
    }
  ],

  "business_impact": {
    "financial": "Significant revenue opportunity: multi-recipient shipments enable consolidated deliveries (one pickup, multiple drops), which can be priced as a premium service. However, pricing models must be redesigned — charging per-recipient-stop vs. per-shipment. Migration costs include engineering effort, partner coordination, and potential downtime. Incorrect migration of 2M records carries financial risk from lost or misrouted deliveries.",
    "operational": "Major operational complexity increase. Courier routing algorithms must handle multi-stop optimization. Shipment status tracking becomes per-recipient, increasing monitoring surface area. Support teams need retraining — a 'delivered' Shipment may now be only 'partially delivered'. SLA definitions must be revisited: does SLA apply per-recipient or per-shipment?",
    "user": "Customers gain flexibility to send to multiple recipients in one transaction. However, tracking UX becomes more complex — customers need to see per-recipient status. Notification systems must send per-recipient delivery updates. Confusion risk is high if the UX doesn't clearly communicate partial delivery states.",
    "risk": "HIGH. This is a change to the core aggregate root of the domain. Risks include: (1) Data migration failure affecting 2M production records, (2) Partner API breakage causing integration failures, (3) Incorrect status tracking leading to lost deliveries, (4) Billing errors from pricing model gaps, (5) Legal risk if proof-of-delivery is not captured per-recipient. The change is irreversible in practice — once multi-recipient shipments exist in production, you cannot go back to the old model.",
    "stakeholders_affected": [
      { "group": "Customers/Shippers", "impact": "Gain multi-recipient capability but face more complex tracking. Must understand partial delivery states." },
      { "group": "Recipients", "impact": "No change to their experience per delivery, but proof-of-delivery and notifications must remain per-recipient." },
      { "group": "Couriers/Drivers", "impact": "Must handle multi-stop routes. Their apps must show per-recipient delivery instructions and capture per-recipient proof-of-delivery." },
      { "group": "External API Partners", "impact": "Breaking change risk. Must be migrated to new API version or receive backward-compatible responses. Partner coordination timeline is a critical path dependency." },
      { "group": "Finance/Billing Team", "impact": "Pricing model must be redesigned before launch. Cannot bill a 5-recipient shipment the same as a 1-recipient shipment." },
      { "group": "Customer Support", "impact": "Must be trained on new partial-delivery states. Support tooling must show per-recipient status. Ticket complexity will increase." },
      { "group": "Operations/Dispatch", "impact": "Route optimization algorithms must be updated. Capacity planning changes — one shipment now consumes multiple delivery slots." }
    ]
  },

  "confidence": {
    "level": 62,
    "reasoning": "The spec clearly states the cardinality change (1-to-many) and mentions delivery preferences, but leaves critical domain questions unanswered: What constitutes 'delivery preferences'? Is there a maximum recipient count? Can recipients be added mid-transit? How does pricing change? What is the Shipment-level status model when recipients have independent statuses? These gaps are material — implementation without answers will force engineers to guess at business rules.",
    "high_confidence_areas": [
      "The 1-to-many cardinality change and its structural implications",
      "Backward compatibility requirement for 2M existing records",
      "Need for per-recipient status tracking",
      "Partner API backward compatibility requirement"
    ],
    "low_confidence_areas": [
      "Definition and scope of 'delivery preferences' — the spec does not enumerate what preferences exist",
      "Pricing and billing model for multi-recipient shipments",
      "Whether recipients can be added or removed after shipment creation",
      "Maximum recipient count per shipment",
      "SLA definition: per-shipment or per-recipient",
      "Shipment-level status semantics when recipients have mixed statuses"
    ],
    "assumptions": [
      "Legacy single-recipient shipments should be treated as multi-recipient shipments with exactly one recipient (structural migration, not a separate code path)",
      "The primary recipient concept exists for backward compatibility with partner APIs",
      "Proof-of-delivery must be captured independently per recipient",
      "The migration must be reversible (rollback capability required)"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'delivery preferences' but does not define what preferences are available. Is this time-window, safe-place, signature-required, authority-to-leave, or something else? The domain model cannot be correctly designed without enumerating the preference types.",
      "affected_stakeholders": ["Customers/Shippers", "Couriers/Drivers", "Engineering"],
      "options": ["Product team provides an exhaustive list of delivery preferences", "Engineering implements a generic key-value preference model (risks domain drift)", "Start with a known subset and iterate"],
      "recommendation": "Product team must provide the enumerated list of delivery preferences before implementation begins. A generic key-value model is an anti-pattern in domain modeling — it obscures business rules."
    },
    {
      "type": "ambiguity",
      "description": "The overall Shipment status model is undefined for multi-recipient scenarios. When Recipient A is delivered and Recipient B is failed, what is the Shipment status? 'Partially delivered'? 'In progress'? This affects every downstream consumer of shipment status — dashboards, partner APIs, SLA calculations, billing triggers.",
      "affected_stakeholders": ["Customers/Shippers", "Customer Support", "Finance/Billing Team", "External API Partners"],
      "options": ["Introduce a 'partially delivered' shipment status", "Shipment status becomes a computed aggregate of recipient statuses", "Shipment status is deprecated in favor of per-recipient status only"],
      "recommendation": "Introduce explicit partial-delivery states at the Shipment level, computed from recipient statuses. This preserves backward compatibility while accurately reflecting reality."
    },
    {
      "type": "missing_context",
      "description": "No pricing or billing model has been defined for multi-recipient shipments. This is not a technical detail — it is a core business decision that affects revenue. A 5-stop shipment costs more to fulfill than a 1-stop shipment. Without a pricing model, the feature cannot be shipped.",
      "affected_stakeholders": ["Finance/Billing Team", "Customers/Shippers", "Operations/Dispatch"],
      "options": ["Price per recipient/stop", "Tiered pricing (1 recipient, 2-5 recipients, 5+ recipients)", "Flat rate per shipment regardless of recipient count"],
      "recommendation": "Finance must define the pricing model before engineering begins. Suggest per-stop pricing as it aligns with the physical cost structure of multi-drop deliveries."
    },
    {
      "type": "ambiguity",
      "description": "Can recipients be added to or removed from a Shipment after creation? If so, up to what lifecycle stage? This has major implications for routing, billing, and partner data sync.",
      "affected_stakeholders": ["Customers/Shippers", "Couriers/Drivers", "Operations/Dispatch"],
      "options": ["Recipients are immutable after shipment creation", "Recipients can be modified until dispatch", "Recipients can be modified at any time with re-routing"],
      "recommendation": "Allow recipient modification only before dispatch. Post-dispatch changes introduce routing complexity and SLA risk that should be deferred to a future iteration."
    }
  ],

  "rejection_reasons": []
}

